// Extract + normalize lead data from various form providers
const body = $json.body || $json;

// Tally sends fields in `data.fields[]` array; Typeform in `form_response.answers`
// Generic POST sends top-level keys. Handle all 3.
function extract(b) {
  // Tally
  if (b.data?.fields) {
    const out = {};
    for (const f of b.data.fields) {
      out[f.label?.toLowerCase()] = f.value;
    }
    return out;
  }
  // Typeform
  if (b.form_response?.answers) {
    const out = {};
    for (const a of b.form_response.answers) {
      out[a.field?.title?.toLowerCase()] = a.text || a.email || a.choice?.label || a.number;
    }
    return out;
  }
  // Generic
  return b;
}

const raw = extract(body);

const lead = {
  email: (raw.email || raw['이메일'] || '').toString().trim(),
  name: (raw.name || raw['이름'] || raw['성함'] || '').toString().trim(),
  company: (raw.company || raw['회사'] || '').toString().trim(),
  role: (raw.role || raw['직책'] || raw['포지션'] || '').toString().trim(),
  message: (raw.message || raw['문의'] || '').toString().trim(),
  utm_source: raw.utm_source || '',
  utm_campaign: raw.utm_campaign || '',
  received_at: new Date().toISOString(),
};

if (!lead.email || !lead.email.includes('@')) {
  throw new Error('Invalid email in form submission');
}

return [{ json: lead }];

// Merge Apollo enrichment into lead. Tolerate failure.
const lead = $('Normalize Lead').item.json;
const apollo = $json?.person || {};

const enriched = {
  ...lead,
  company: lead.company || apollo.organization?.name || '',
  role: lead.role || apollo.title || '',
  domain: apollo.organization?.website_url || apollo.organization?.primary_domain || '',
  linkedin_url: apollo.linkedin_url || '',
  industry: apollo.organization?.industry || '',
  company_size: apollo.organization?.estimated_num_employees || null,
};
return [{ json: enriched }];

