try {
  parsed = typeof raw === 'string' ? JSON.parse(raw.replace(/^```json\s*|\s*```$/g, '')) : raw;
} catch (e) {
  parsed = { score: 50, persona: 'other', hot_signal: false, reasoning: 'parse failed' };
}
const lead = $('Merge Enrichment').item.json;
return [{ json: { ...lead, ...parsed } }];

